#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;ll L,R;
#define int ll
const int Mod=998244353;template<typename T> inline void DN(T &x){x>=Mod?x-=Mod:0;}
int K,n,a[20],cnt[1024];ll dp[20][1024][10][2],g[20][1024][10][2],pw[20];
inline ll S(ll k)
{
	n=0;while(k)a[++n]=k%10,k/=10;
	memset(dp,0,sizeof(dp));
	memset(g,0,sizeof(g));
	rep(0,9,i)dp[1][1<<i][i][0]=1,g[1][1<<i][i][0]=i;
	rep(0,a[1],i)dp[1][1<<i][i][1]=1,g[1][1<<i][i][1]=i;
	
	rep(1,n-1,d)
	{
		for(int S=1;S<(1<<10);++S)
		{
			rep(0,9,i)
			{
				ll *w=dp[d][S][i],*wg=g[d][S][i];
				rep(0,9,j)
				{
					int nS=S|(1<<j);
					DN(dp[d+1][nS][j][0]+=w[0]);
					DN(g[d+1][nS][j][0]+=(1ll*j*pw[d]%Mod*w[0]%Mod+wg[0])%Mod);
					if(j<a[d+1])
					{
						DN(dp[d+1][nS][j][1]+=w[0]);
						DN(g[d+1][nS][j][1]+=(1ll*j*pw[d]%Mod*w[0]%Mod+wg[0])%Mod);
					}
					else if(j==a[d+1])
					{
						DN(dp[d+1][nS][j][1]+=w[1]);
						DN(g[d+1][nS][j][1]+=((1ll*j*pw[d]%Mod*w[1]%Mod+wg[1])%Mod));
					}
				}
			}
		}
	}
	ll ans=0;
	rep(1,n-1,d)
	{
		for(int S=1;S<(1<<10);++S)if(cnt[S]<=K)
		{
			rep(1,9,i)DN(ans+=g[d][S][i][0]);
		}
	}
	for(int S=1;S<(1<<10);++S)if(cnt[S]<=K)
	{
		rep(1,a[n]-1,i)DN(ans+=g[n][S][i][0]);
		DN(ans+=g[n][S][a[n]][1]);
	}
	return ans;
}
signed main()
{
	
	for(int S=1;S<(1<<10);++S)cnt[S]=cnt[S>>1]+(S&1);
	pw[0]=1;rep(1,19,i)pw[i]=pw[i-1]*10%Mod;K=2;
	scanf("%lld%lld%lld",&L,&R,&K);printf("%lld\n",(S(R)-S(L-1)+Mod)%Mod);
}
